CREATE TABLE IF NOT EXISTS stock_returns(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),warehouse_id uuid NOT NULL REFERENCES warehouses(id)ON DELETE CASCADE,return_no text NOT NULL,kind text NOT NULL CHECK(kind IN('customer','supplier')),original_document_id uuid NOT NULL REFERENCES stock_documents(id),status text NOT NULL DEFAULT'draft'CHECK(status IN('draft','confirmed','cancelled')),return_document_id uuid REFERENCES stock_documents(id),created_by uuid REFERENCES users(id),confirmed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(warehouse_id,return_no));
CREATE TABLE IF NOT EXISTS stock_return_lines(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),return_id uuid NOT NULL REFERENCES stock_returns(id)ON DELETE CASCADE,original_movement_id uuid NOT NULL REFERENCES stock_movements(id),quantity numeric(18,4)NOT NULL CHECK(quantity>0),UNIQUE(return_id,original_movement_id));
CREATE INDEX IF NOT EXISTS idx_returns_scope ON stock_returns(warehouse_id,status,created_at DESC);
